346 struct FrameBufferChain{
347     private:
351         FrameBufferChain() = delete;
352         int size = 0;
353         std::vector<std::shared_ptr<FrameBuffer>> frameBufferPtrArray;
354     public:
359         FrameBufferChain(int s) : size(s) {
360             frameBufferPtrArray.resize(s);
361         };
362 
368         std::shared_ptr<FrameBuffer> getAtIndex(int index){
369             if(index < 0 || index >= size) return nullptr;
370             return frameBufferPtrArray[index];
371         }
372 
378         void setAtIndex(int index, std::shared_ptr<FrameBuffer> fbPtr){
379             if(index < 0 || index >= size) return;
380             frameBufferPtrArray[index] = fbPtr;
381         }
382 
387         int getSize(){
388             return size;
389         }
390 
395         void resize(int newSize){
396             if(newSize <= 0) return;
397             frameBufferPtrArray.resize(newSize);
398             size = newSize;
399         }
400 
406         void resizeBuffers(int width, int height){
407             for(auto buffer : frameBufferPtrArray){
408                 if(buffer) {
409                     buffer->resize(width,height);
410                 }
411             }
412         }
413 };
414 
416 struct TrippleBuffer{
417     private:
418         FrameBufferChain chain = FrameBufferChain(3);
419         int width, height;
423         TrippleBuffer() = delete;
424     public:
425 
431         TrippleBuffer(int width, int height) : width(width), height(height) {
432             chain.setAtIndex(0, FrameBuffer::Create(width, height));
433             chain.setAtIndex(1, FrameBuffer::Create(width, height));
434             chain.setAtIndex(2, FrameBuffer::Create(width, height));
435         }
436 
441         std::shared_ptr<FrameBuffer> getFront(){
442             return chain.getAtIndex(0);
443         }
444         
449         std::shared_ptr<FrameBuffer> getMiddle(){
450             return chain.getAtIndex(1);
451         }
452 
457         std::shared_ptr<FrameBuffer> getBack(){
458             return chain.getAtIndex(2);
459         }
460 
461 
462         // Helper functions for understanding the order.
463 
464         std::shared_ptr<FrameBuffer> getDisplayBuffer(){
465             return getFront();
466         }
467 
472         std::shared_ptr<FrameBuffer> getEditBuffer(){
473             return getMiddle();
474         }
475 
480         std::shared_ptr<FrameBuffer> getDrawBuffer(){
481             return getBack();
482         }
483 
484         // ===================================================
485 
486         void setFront(std::shared_ptr<FrameBuffer> framePtr){
487             chain.setAtIndex(0,framePtr);
488         }
489 
494         void setMiddle(std::shared_ptr<FrameBuffer> framePtr){
495             chain.setAtIndex(1,framePtr);
496         }
497 
502         void setBack(std::shared_ptr<FrameBuffer> framePtr){
503             chain.setAtIndex(2,framePtr);
504         }
505 
509         void swapBuffers(){
510             auto frontBuffer = getFront();
511             auto middleBuffer = getMiddle();
512             auto backBuffer = getBack();
513 
514             setFront(middleBuffer);
515             setMiddle(backBuffer);
516             setBack(frontBuffer);
517         }
518 
524         void resizeBuffers(int width, int height){
525             chain.resizeBuffers(width, height);
526         }
527 };
